38	typedef enum datatype_enum {
39	    TYPE_INVALID,
40	    TYPE_BOOL,
41	    TYPE_UINT8,
42	    TYPE_UINT16,
43	    TYPE_UINT32,
44	    TYPE_UINT64,
45	    TYPE_INT8,
46	    TYPE_INT16,
47	    TYPE_INT32,
48	    TYPE_INT64,
49	    TYPE_FP16,
50	    TYPE_FP32,
51	    TYPE_FP64,
52	    TYPE_BYTES,
53	    TYPE_BF16,
54	    TYPE_FP8_E4M3,
55	    TYPE_STR,
56	    TYPE_VOID,
57	} DataType;
58	
59	template<typename T>
60	DataType getTensorType()
61	{
62	    if (std::is_same<T, float>::value || std::is_same<T, const float>::value) {
63	        return TYPE_FP32;
64	    }
65	    else if (std::is_same<T, half>::value || std::is_same<T, const half>::value) {
66	        return TYPE_FP16;
67	    }
68	#ifdef ENABLE_BF16
69	    else if (std::is_same<T, __nv_bfloat16>::value || std::is_same<T, const __nv_bfloat16>::value) {
70	        return TYPE_BF16;
71	    }
72	#endif
73	#ifdef ENABLE_FP8
74	    else if (std::is_same<T, __nv_fp8_e4m3>::value || std::is_same<T, const __nv_fp8_e4m3>::value) {
75	        return TYPE_FP8_E4M3;
76	    }
77	#endif
78	    else if (std::is_same<T, int>::value || std::is_same<T, const int>::value) {
79	        return TYPE_INT32;
80	    }
81	    else if (std::is_same<T, int8_t>::value || std::is_same<T, const int8_t>::value) {
82	        return TYPE_INT8;
83	    }
84	    else if (std::is_same<T, uint>::value || std::is_same<T, const uint>::value) {
85	        return TYPE_UINT32;
86	    }
87	    else if (std::is_same<T, unsigned long long int>::value || std::is_same<T, const unsigned long long int>::value) {
88	        return TYPE_UINT64;
89	    }
90	    else if (std::is_same<T, bool>::value || std::is_same<T, const bool>::value) {
91	        return TYPE_BOOL;
92	    }
93	    else if (std::is_same<T, char>::value || std::is_same<T, const char>::value) {
94	        return TYPE_BYTES;
95	    }
96	    else {
97	        return TYPE_INVALID;
98	    }
99	}
