107	struct Tensor {
108	    const MemoryType          where;
109	    const DataType            type;
110	    const std::vector<size_t> shape;
111	    const void*               data;  // TODO(bhseuh) modify from const void* to void* const
112	    const std::vector<size_t> offsets = std::vector<size_t>{};
113	
114	    Tensor();
115	    Tensor(const MemoryType _where, const DataType _type, const std::vector<size_t> _shape, const void* _data);
116	    Tensor(const MemoryType          _where,
117	           const DataType            _type,
118	           const std::vector<size_t> _shape,
119	           const void*               _data,
120	           const std::vector<size_t> _offset);
121	
122	    size_t size() const;
123	    size_t sizeBytes() const;
124	
125	    std::string whereToString() const;
126	    std::string toString() const;
127	    std::string getNumpyTypeDesc(DataType type) const;
128	
129	    void          saveNpy(const std::string& filename) const;
130	    static Tensor loadNpy(const std::string& npy_file, const MemoryType where);
131	
132	    static DataType typeFromNumpyDesc(std::string type);
133	    static size_t   getTypeSize(DataType type);
134	
135	    template<typename T>
136	    inline T getVal(size_t index) const
137	    {
138	        FT_LOG_DEBUG("%s start", __PRETTY_FUNCTION__);
139	        FT_CHECK(where == MEMORY_CPU);
140	        FT_CHECK(data != nullptr);
141	        FT_CHECK_WITH_INFO(index < size(), "index is larger than buffer size");
142	
143	        if (getTensorType<T>() != type) {
144	            FT_LOG_DEBUG("getVal with type %s, but data type is: %s",
145	                         getNumpyTypeDesc(getTensorType<T>()).c_str(),
146	                         getNumpyTypeDesc(type).c_str());
147	        }
148	        return ((T*)data)[index];
149	    }
150	
151	    template<typename T>
152	    inline T getVal() const
153	    {
154	        FT_LOG_DEBUG("%s start", __PRETTY_FUNCTION__);
155	        if (getTensorType<T>() != type) {
156	            FT_LOG_DEBUG("getVal with type %s, but data type is: %s",
157	                         getNumpyTypeDesc(getTensorType<T>()).c_str(),
158	                         getNumpyTypeDesc(type).c_str());
159	        }
160	        return getVal<T>(0);
161	    }
162	
163	    template<typename T>
164	    inline T* getPtr() const
165	    {
166	        FT_LOG_DEBUG("%s start", __PRETTY_FUNCTION__);
167	        if (getTensorType<T>() != type) {
168	            FT_LOG_DEBUG("getPtr with type %s, but data type is: %s",
169	                         getNumpyTypeDesc(getTensorType<T>()).c_str(),
170	                         getNumpyTypeDesc(type).c_str());
171	        }
172	        return (T*)data;
173	    }
174	
175	    inline void* getPtrWithOffset(size_t offset) const
176	    {
177	        FT_LOG_DEBUG("%s start", __PRETTY_FUNCTION__);
178	        if (data == nullptr) {
179	            return (void*)data;
180	        }
181	        else {
182	            FT_CHECK_WITH_INFO(offset < size(), "offset is larger than buffer size");
183	            return (void*)((char*)data + offset * Tensor::getTypeSize(type));
184	        }
185	    }
186	
187	    template<typename T>
188	    inline T* getPtrWithOffset(size_t offset) const
189	    {
190	        FT_LOG_DEBUG("%s start", __PRETTY_FUNCTION__);
191	        if (getTensorType<T>() != type) {
192	            FT_LOG_DEBUG("getVal with type %s, but data type is: %s",
193	                         getNumpyTypeDesc(getTensorType<T>()).c_str(),
194	                         getNumpyTypeDesc(type).c_str());
195	        }
196	        if (data == nullptr) {
197	            return (T*)data;
198	        }
199	        else {
200	            FT_CHECK_WITH_INFO(offset < size(),
201	                               fmtstr("offset (%lu) is larger than buffer size (%lu)", offset, size()));
202	            return ((T*)data) + offset;
203	        }
204	    }
205	
206	    template<typename T>
207	    T max() const
208	    {
209	        if (getTensorType<T>() != type) {
210	            FT_LOG_DEBUG("getVal with type %s, but data type is: %s",
211	                         getNumpyTypeDesc(getTensorType<T>()).c_str(),
212	                         getNumpyTypeDesc(type).c_str());
213	        }
214	        FT_CHECK_WITH_INFO(shape.size() > 0 && data != nullptr, "Should be a non-empty tensor.");
215	        FT_CHECK_WITH_INFO(where == MEMORY_CPU || where == MEMORY_CPU_PINNED,
216	                           "max() supports MEMORY_CPU or MEMORY_CPU_PINNED tensor.");
217	        size_t max_idx = 0;
218	        T      max_val = getVal<T>(max_idx);
219	        for (size_t i = 1; i < size(); ++i) {
220	            T val = getVal<T>(i);
221	            if (val > max_val) {
222	                max_idx = i;
223	                max_val = val;
224	            }
225	        }
226	        return max_val;
227	    }
228	
229	    template<typename T>
230	    T min() const
231	    {
232	        if (getTensorType<T>() != type) {
233	            FT_LOG_DEBUG("getVal with type %s, but data type is: %s",
234	                         getNumpyTypeDesc(getTensorType<T>()).c_str(),
235	                         getNumpyTypeDesc(type).c_str());
236	        }
237	        FT_CHECK_WITH_INFO(shape.size() > 0 && data != nullptr, "Should be a non-empty tensor.");
238	        FT_CHECK_WITH_INFO(where == MEMORY_CPU || where == MEMORY_CPU_PINNED,
239	                           "min() supports MEMORY_CPU or MEMORY_CPU_PINNED tensor.");
240	        size_t min_idx = 0;
241	        T      min_val = getVal<T>(min_idx);
242	        for (size_t i = 1; i < size(); ++i) {
243	            T val = getVal<T>(i);
244	            if (val < min_val) {
245	                min_idx = i;
246	                min_val = val;
247	            }
248	        }
249	        return min_val;
250	    }
251	
252	    template<typename T>
253	    T any(T val) const
254	    {
255	        if (getTensorType<T>() != type) {
256	            FT_LOG_DEBUG("getVal with type %s, but data type is: %s",
257	                         getNumpyTypeDesc(getTensorType<T>()).c_str(),
258	                         getNumpyTypeDesc(type).c_str());
259	        }
260	        FT_CHECK_WITH_INFO(shape.size() > 0 && data != nullptr, "Should be a non-empty tensor.");
261	        FT_CHECK_WITH_INFO(where == MEMORY_CPU || where == MEMORY_CPU_PINNED,
262	                           "any() supports MEMORY_CPU or MEMORY_CPU_PINNED tensor.");
263	        for (size_t i = 0; i < size(); ++i) {
264	            if (getVal<T>(i) == val) {
265	                return true;
266	            }
267	        }
268	        return false;
269	    }
270	
271	    template<typename T>
272	    T all(T val) const
273	    {
274	        if (getTensorType<T>() != type) {
275	            FT_LOG_DEBUG("getVal with type %s, but data type is: %s",
276	                         getNumpyTypeDesc(getTensorType<T>()).c_str(),
277	                         getNumpyTypeDesc(type).c_str());
278	        }
279	        FT_CHECK_WITH_INFO(shape.size() > 0 && data != nullptr, "Should be a non-empty tensor.");
280	        FT_CHECK_WITH_INFO(where == MEMORY_CPU || where == MEMORY_CPU_PINNED,
281	                           "all() supports MEMORY_CPU or MEMORY_CPU_PINNED tensor.");
282	        for (size_t i = 0; i < size(); ++i) {
283	            if (getVal<T>(i) != val) {
284	                return false;
285	            }
286	        }
287	        return true;
288	    }
289	
290	    void updateShape(size_t idx, size_t val)
291	    {
292	        // TODO: find a better way to update the shape
293	        std::vector<size_t>& shape_ref = const_cast<std::vector<size_t>&>(shape);
294	        shape_ref[idx]                 = val;
