304	class TensorMap {
305	private:
306	    std::unordered_map<std::string, Tensor> tensor_map_;
307	
308	    inline bool isValid(const Tensor& tensor)
309	    {
310	        return tensor.size() > 0 && tensor.data != nullptr;
311	    }
