378	        if (isExist(key)) {
379	            return tensor_map_.at(key);
380	        }
381	        return default_tensor;
382	    }
383	
384	    inline Tensor at(const std::string& key, Tensor& default_tensor) const
385	    {
386	        FT_LOG_DEBUG("%s for key %s", __PRETTY_FUNCTION__, key.c_str());
387	        if (isExist(key)) {
388	            return tensor_map_.at(key);
