469	    {
470	        FT_CHECK_WITH_INFO(isExist(key),
471	                           fmtstr("Cannot find a tensor of name %s in the tensor map (keys: %s)",
472	                                  key.c_str(),
473	                                  vec2str(keys()).c_str()));
474	        return tensor_map_.at(key).getPtrWithOffset<T>(index);
475	    }
476	
477	    template<typename T>
478	    inline T* getPtrWithOffset(const std::string& key, size_t index, T* default_ptr) const
479	    {
480	        if (isExist(key)) {
481	            return tensor_map_.at(key).getPtrWithOffset<T>(index);
482	        }
483	        return default_ptr;
484	    }
485	
486	    inline std::unordered_map<std::string, Tensor> getMap() const
487	    {
488	        return tensor_map_;
489	    }
490	
491	    inline std::unordered_map<std::string, Tensor>::iterator begin()
492	    {
493	        return tensor_map_.begin();
494	    }
495	
496	    inline std::unordered_map<std::string, Tensor>::iterator end()
497	    {
498	        return tensor_map_.end();
499	    }
500	
501	    std::string      toString();
502	    static TensorMap fromNpyFolder(const std::string& base_folder);
503	    void             saveNpy(const std::string& base_folder);
504	};
505	
