60	void Tensor::parseNpyIntro(FILE*& f_ptr, uint32_t& header_len, uint32_t& start_data)
61	{
62	    const char magic[]                   = "\x93"
63	                                           "NUMPY";
64	    char       magic_test[sizeof(magic)] = "\0";
65	
66	    size_t n_elems = fread((void*)magic_test, sizeof(char), sizeof(magic) - 1, f_ptr);
67	    if (n_elems != sizeof(magic) - 1 || std::string(magic) != std::string(magic_test)) {
68	        throw std::runtime_error("Could read magic token in NPY file");
69	    }
70	
71	    uint8_t npy_major = 0;
72	    uint8_t npy_minor = 0;
73	    n_elems           = fread((void*)&npy_major, sizeof(uint8_t), 1, f_ptr);
74	    n_elems += fread((void*)&npy_minor, sizeof(uint8_t), 1, f_ptr);
75	
76	    if (npy_major == 1) {
77	        uint16_t header_len_u16 = 0;
78	        n_elems                 = fread((void*)&header_len_u16, sizeof(uint16_t), 1, f_ptr);
79	        header_len              = header_len_u16;
80	    }
81	    else if (npy_major == 2) {
82	        uint32_t header_len_u32 = 0;
83	        n_elems                 = fread((void*)&header_len_u32, sizeof(uint32_t), 1, f_ptr);
84	        header_len              = header_len_u32;
85	    }
86	    else {
87	        throw std::runtime_error("Unsupported npy version: " + std::to_string(npy_major));
88	    }
89	
90	    start_data = 8 + 2 * npy_major + header_len;
91	}
92	
93	int Tensor::parseNpyHeader(FILE*& f_ptr, uint32_t header_len, DataType& type, std::vector<size_t>& shape)
94	{
95	    char*  header_c = (char*)malloc(header_len * sizeof(char));
96	    size_t n_elems  = fread((void*)header_c, sizeof(char), header_len, f_ptr);
97	    if (n_elems != header_len) {
98	        free(header_c);
99	        return -1;
100	    }
101	    std::string header(header_c, header_len);
102	    free(header_c);
103	
104	    size_t start, end;
105	    start = header.find("'descr'") + 7;
106	    start = header.find("'", start);
107	    end   = header.find("'", start + 1);
108	    type  = typeFromNumpyDesc(header.substr(start + 1, end - start - 1));
109	
110	    start = header.find("'fortran_order'") + 15;
111	    start = header.find(":", start);
112	    end   = header.find(",", start + 1);
113	    if (header.substr(start + 1, end - start - 1).find("False") == std::string::npos) {
114	        throw std::runtime_error("Unsupported value for fortran_order while reading npy file");
115	    }
116	
117	    start = header.find("'shape'") + 7;
118	    start = header.find("(", start);
119	    end   = header.find(")", start + 1);
120	
121	    std::istringstream shape_stream(header.substr(start + 1, end - start - 1));
122	    std::string        token;
123	
124	    shape.clear();
125	    while (std::getline(shape_stream, token, ',')) {
126	        if (token.find_first_not_of(' ') == std::string::npos) {
127	            break;
128	        }
129	        shape.push_back(std::stoul(token));
130	    }
131	
132	    return 0;
133	}
134	
135	Tensor Tensor::loadNpy(const std::string& npy_file, const MemoryType where)
136	{
137	    DataType            type;
138	    std::vector<size_t> shape;
139	
140	    FILE* f_ptr = fopen(npy_file.c_str(), "rb");
141	    if (f_ptr == nullptr) {
142	        throw std::runtime_error("Could not open file " + npy_file);
143	    }
144	    uint32_t header_len, start_data;
145	    parseNpyIntro(f_ptr, header_len, start_data);
146	    parseNpyHeader(f_ptr, header_len, type, shape);
147	
148	    const size_t size     = std::accumulate(shape.begin(), shape.end(), 1, std::multiplies<size_t>());
149	    void*        data_cpu = malloc(size * Tensor::getTypeSize(type));
150	    void*        data     = data_cpu;
151	
152	    size_t n_elems = fread(data_cpu, Tensor::getTypeSize(type), size, f_ptr);
153	    FT_CHECK_WITH_INFO(n_elems == size, "reading tensor failed");
154	    if (where == MEMORY_GPU) {
155	        cudaMalloc(&data, size * Tensor::getTypeSize(type));
156	        cudaMemcpy(data, data_cpu, size * Tensor::getTypeSize(type), cudaMemcpyHostToDevice);
157	        free(data_cpu);
158	    }
159	
160	    fclose(f_ptr);
161	    return Tensor(where, type, shape, data);
162	}
