214	DataType Tensor::typeFromNumpyDesc(std::string type)
215	{
216	    static const std::unordered_map<std::string, DataType> type_map{{"?", TYPE_BOOL},
217	                                                                    {"b", TYPE_BYTES},
218	                                                                    {"u1", TYPE_UINT8},
219	                                                                    {"u2", TYPE_UINT16},
