295	    const char    magic[]   = "\x93"
296	                              "NUMPY";
297	    const uint8_t npy_major = 1;
298	    const uint8_t npy_minor = 0;
299	
300	    std::stringstream header_stream;
301	    header_stream << "{'descr': '" << getNumpyTypeDesc(type) << "', 'fortran_order': False, 'shape': (";
302	    for (size_t i = 0; i < shape.size(); ++i) {
303	        header_stream << shape[i];
304	        if (i + 1 < shape.size() || shape.size() == 1) {
305	            header_stream << ", ";
306	        }
307	    }
308	    header_stream << ")}";
309	    int base_length = 6 + 4 + header_stream.str().size();
310	    int pad_length  = 16 * ((base_length + 1 + 15) / 16);  // Take ceiling of base_length + 1 (for '\n' ending)
311	    for (int i = 0; i < pad_length - base_length; ++i) {
312	        header_stream << ((i == pad_length - base_length - 1) ? "\n" : "\x20");
313	    }
314	    std::string    header     = header_stream.str();
315	    const uint16_t header_len = header.size();
316	
317	    FILE* f_ptr = fopen(filename.c_str(), "wb");
318	    FT_CHECK_WITH_INFO(f_ptr != nullptr, fmtstr("Unable to open %s for writing.\n", filename.c_str()));
