321	    fwrite(&npy_major, sizeof(uint8_t), 1, f_ptr);
322	    fwrite(&npy_minor, sizeof(uint8_t), 1, f_ptr);
323	    fwrite(&header_len, sizeof(uint16_t), 1, f_ptr);
324	    fwrite(header.c_str(), sizeof(char), header_len, f_ptr);
325	    fwrite(cpu_data, Tensor::getTypeSize(type), tensor_size, f_ptr);
326	
327	    fclose(f_ptr);
328	
329	    if (is_data_temp) {
330	        free(cpu_data);
