408	TensorMap TensorMap::fromNpyFolder(const std::string& base_folder)
409	{
410	    DIR* dir_p = opendir(base_folder.c_str());
411	    FT_CHECK_WITH_INFO(dir_p != nullptr, fmtstr("Could not open folder %s. ", base_folder.c_str()));
412	    struct dirent* dp;
413	
414	    TensorMap ret_tensor;
415	    while ((dp = readdir(dir_p)) != nullptr) {
416	        std::string filename(dp->d_name);
417	        size_t      len = filename.length();
418	        if (len < 4 || filename.compare(len - 4, 4, ".npy")) {
419	            continue;
420	        }
421	
422	        size_t pos = filename.find('-');
423	        FT_CHECK_WITH_INFO(pos != std::string::npos, fmtstr("Invalid filename: %s\n", filename.c_str()));
424	
425	        MemoryType where;
426	        if (filename.compare(0, pos, "GPU") == 0) {
427	            where = MEMORY_GPU;
428	        }
429	        else if (filename.compare(0, pos, "CPU") == 0) {
430	            where = MEMORY_CPU;
431	        }
432	        else if (filename.compare(0, pos, "CPU_PINNED") == 0) {
433	            where = MEMORY_CPU_PINNED;
434	        }
435	        else {
436	            FT_CHECK_WITH_INFO(false, fmtstr("Invalid filename: %s\n", filename.c_str()));
437	        }
438	        std::string key = filename.substr(pos + 1, len - pos - 5);
439	
440	        ret_tensor.tensor_map_.insert({key, Tensor::loadNpy(base_folder + "/" + filename, where)});
441	    }
442	
443	    closedir(dir_p);
444	
445	    return ret_tensor;
446	}
