449	{
450	    mode_t mode_0755 = S_IRWXU | S_IRGRP | S_IXGRP | S_IROTH | S_IXOTH;
451	    int    ret       = mkdir(base_folder.c_str(), mode_0755);
452	    FT_CHECK_WITH_INFO(ret == 0 || errno == EEXIST, fmtstr("Could not create folder %s.\n", base_folder.c_str()));
453	
454	    for (const auto& item : tensor_map_) {
455	        item.second.saveNpy(base_folder + "/" + item.second.whereToString() + "-" + item.first + ".npy");
456	    }
457	}
